import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    """
    {The algorithm prioritizes selecting the next customer by minimizing a dynamic priority score that incorporates travel time, adjusted waiting,
    collaborative truck redistribution, and non-linear penalties for excessively deviating from time windows, emphasizing strategic choice adjustments.}
    """
    def travel_time(pos1, pos2):
        return np.linalg.norm(pos1 - pos2) / truck_speed

    dynamic_penalty_weight = 500  # Adjusts based on customer's criticality
    score_multiplier = 1.5  # Multiplies score based on time urgency
    best_score = float('inf')
    best_node = None

    for i, customer in enumerate(unvisited_customers):
        time_to_customer = travel_time(cur_truck_pos, customer)
        arrival_time = current_time + time_to_customer
        start_window, end_window = time_windows[i]

        # Penalty calculation using a non-linear approach
        if arrival_time > end_window:
            penalty = dynamic_penalty_weight * np.square(arrival_time - end_window)
        elif arrival_time < start_window:
            penalty = dynamic_penalty_weight * np.square(start_window - arrival_time)
        else:
            penalty = 0

        # Incorporate a dynamic score multiplier
        if penalty > 0:
            total_score = (time_to_customer + penalty) * score_multiplier
        else:
            total_score = time_to_customer

        urgen_factor = len(all_truck_pos) / (np.count_nonzero(np.array([arrival_time <= tw[1] for tw in time_windows])))
        total_score *= urgen_factor

        if total_score < best_score:
            best_score = total_score
            best_node = i

    if best_score == float('inf'):
        best_node = None

    return best_node
